previewCss:
.darma-loader-typing-dots {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  border-radius: 999px;
  background: rgba(99, 102, 241, 0.1);
  padding: 13px 16px;
  color: #6366f1;
}
.darma-loader-typing-dots i {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: currentColor;
  animation: darma-loader-typing-dots-typing 1.05s ease-in-out infinite;
}
.darma-loader-typing-dots i:nth-child(2) { animation-delay: 0.16s; }
.darma-loader-typing-dots i:nth-child(3) { animation-delay: 0.32s; }
@keyframes darma-loader-typing-dots-typing {
  0%, 80%, 100% { transform: translateY(0); opacity: 0.35; }
  40% { transform: translateY(-7px); opacity: 1; }
}

